/* ============================================================
   Agent Tracer — 可观测追踪系统
   记录每次 Agent 调用的输入/输出/耗时/状态
   提供事件订阅机制供 Dashboard 消费
   ============================================================ */

// === 追踪记录类型 ===
export type AgentName =
  | 'intent-router'
  | 'jd-generator'
  | 'resume-parser'
  | 'screening-scorer'
  | 'progress-tracker';

export type TraceStatus = 'pending' | 'running' | 'success' | 'error' | 'timeout';

export interface AgentTrace {
  id: string;
  agentName: AgentName;
  status: TraceStatus;
  startTime: number;
  endTime?: number;
  duration?: number;          // ms
  input: string;              // summary/preview of input
  inputDetail?: string;       // full input for inspection
  output?: string;            // summary/preview of output
  outputDetail?: string;      // full output for inspection
  error?: string;
  tags: Record<string, string>;  // conversationId, intent, state, etc.
  metadata?: Record<string, unknown>;
}

export interface TraceSummary {
  totalCalls: number;
  successCount: number;
  errorCount: number;
  avgDuration: number;
  recentTraces: AgentTrace[];
}

// === 事件类型 ===
export type TracerEventType = 'trace-start' | 'trace-complete' | 'trace-error' | 'traces-cleared';

export interface TracerEvent {
  type: TracerEventType;
  trace?: AgentTrace;
  timestamp: number;
}

type TracerSubscriber = (event: TracerEvent) => void;

// ============================================================
// Tracer 类
// ============================================================
export class AgentTracer {
  private traces: AgentTrace[] = [];
  private subscribers: Set<TracerSubscriber> = new Set();
  private maxTraces: number;
  private enabled: boolean = true;
  private activeTraces: Map<string, AgentTrace> = new Map();

  constructor(maxTraces: number = 200) {
    this.maxTraces = maxTraces;
  }

  /** 开启/关闭追踪 */
  setEnabled(enabled: boolean) {
    this.enabled = enabled;
  }

  /** 订阅事件 */
  subscribe(fn: TracerSubscriber): () => void {
    this.subscribers.add(fn);
    return () => this.subscribers.delete(fn);
  }

  /** 发起事件 */
  private emit(event: TracerEvent) {
    for (const fn of this.subscribers) {
      try { fn(event); } catch { /* ignore subscriber errors */ }
    }
  }

  /** 开始追踪 */
  startTrace(
    agentName: AgentName,
    input: string,
    tags: Record<string, string> = {},
    inputDetail?: string,
  ): string {
    if (!this.enabled) return '';

    const id = `trace_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`;
    const trace: AgentTrace = {
      id,
      agentName,
      status: 'running',
      startTime: Date.now(),
      input,
      inputDetail,
      tags,
    };

    this.activeTraces.set(id, trace);
    this.traces.unshift(trace);
    this.trimTraces();

    this.emit({ type: 'trace-start', trace, timestamp: Date.now() });
    return id;
  }

  /** 完成追踪 */
  completeTrace(id: string, output: string, outputDetail?: string, metadata?: Record<string, unknown>) {
    if (!this.enabled || !id) return;

    const trace = this.activeTraces.get(id);
    if (!trace) return;

    trace.status = 'success';
    trace.endTime = Date.now();
    trace.duration = trace.endTime - trace.startTime;
    trace.output = output;
    trace.outputDetail = outputDetail;
    if (metadata) trace.metadata = metadata;

    this.activeTraces.delete(id);
    this.emit({ type: 'trace-complete', trace: { ...trace }, timestamp: Date.now() });
  }

  /** 追踪错误 */
  errorTrace(id: string, error: string) {
    if (!this.enabled || !id) return;

    const trace = this.activeTraces.get(id);
    if (!trace) return;

    trace.status = 'error';
    trace.endTime = Date.now();
    trace.duration = trace.endTime - trace.startTime;
    trace.error = error;

    this.activeTraces.delete(id);
    this.emit({ type: 'trace-error', trace: { ...trace }, timestamp: Date.now() });
  }

  /** 获取所有追踪记录 */
  getTraces(filter?: {
    agentName?: AgentName;
    status?: TraceStatus;
    limit?: number;
  }): AgentTrace[] {
    let result = [...this.traces];
    if (filter?.agentName) {
      result = result.filter(t => t.agentName === filter.agentName);
    }
    if (filter?.status) {
      result = result.filter(t => t.status === filter.status);
    }
    return result.slice(0, filter?.limit ?? 50);
  }

  /** 获取追踪摘要 */
  getSummary(): TraceSummary {
    const completed = this.traces.filter(t => t.status !== 'running' && t.status !== 'pending');
    const successCount = this.traces.filter(t => t.status === 'success').length;
    const errorCount = this.traces.filter(t => t.status === 'error' || t.status === 'timeout').length;
    const durations = completed.map(t => t.duration ?? 0).filter(d => d > 0);
    const avgDuration = durations.length > 0
      ? Math.round(durations.reduce((a, b) => a + b, 0) / durations.length)
      : 0;

    return {
      totalCalls: this.traces.length,
      successCount,
      errorCount,
      avgDuration,
      recentTraces: this.traces.slice(0, 20),
    };
  }

  /** 清除追踪 */
  clearTraces() {
    this.traces = [];
    this.activeTraces.clear();
    this.emit({ type: 'traces-cleared', timestamp: Date.now() });
  }

  /** 获取活跃（正在运行）的追踪 */
  getActiveTraces(): AgentTrace[] {
    return Array.from(this.activeTraces.values());
  }

  /** 按标签过滤 */
  getTracesByTag(key: string, value: string): AgentTrace[] {
    return this.traces.filter(t => t.tags[key] === value);
  }

  private trimTraces() {
    if (this.traces.length > this.maxTraces) {
      this.traces = this.traces.slice(0, this.maxTraces);
    }
  }
}

// ============================================================
// 全局单例
// ============================================================
let tracerInstance: AgentTracer | null = null;

export function getAgentTracer(): AgentTracer {
  if (!tracerInstance) {
    tracerInstance = new AgentTracer(200);
  }
  return tracerInstance;
}

export function resetAgentTracer(): void {
  tracerInstance = null;
}

/* ============================================================
   DocumentParser — 文档解析工具
   混合方案：
   - .txt  → 直接读取
   - .docx  → mammoth.js 提取
   - PDF 文本型 → pdf.js 文本提取
   - PDF 扫描型 → pdf.js Canvas → Base64 图片（供 LLM Vision）

   Worker 加载策略：
   1. Vite dev/prod: 通过 ?url import → Vite 统一处理
   2. Fallback: CDN URL（若 import 失败）
   ============================================================ */

import * as pdfjsLib from 'pdfjs-dist';

// Vite 原生 worker URL 导入 — dev 和 prod 模式下均正确
import pdfjsWorkerUrl from 'pdfjs-dist/build/pdf.worker.min.mjs?url';

// 设置 Worker 源
try {
  pdfjsLib.GlobalWorkerOptions.workerSrc = pdfjsWorkerUrl;
} catch {
  // 极端异常时使用 CDN fallback
  const version = '6.0.227';
  pdfjsLib.GlobalWorkerOptions.workerSrc = `https://cdnjs.cloudflare.com/ajax/libs/pdf.js/${version}/pdf.worker.min.mjs`;
  console.warn('[DocumentParser] Worker import failed, using CDN fallback');
}

import mammoth from 'mammoth';

// ============================================================
// 类型定义
// ============================================================

/** 解析来源 */
export type ParseSource = 'txt' | 'docx' | 'pdf_text' | 'pdf_scanned';

/** 文档解析结果 */
export interface ParsedDocument {
  /** 提取的纯文本 */
  text: string;
  /** 解析来源 */
  source: ParseSource;
  /** 是否为扫描版（需要 Vision 进一步处理） */
  isScanned: boolean;
  /** Markdown 渲染用文件名 */
  fileName: string;
  /** 扫描版 PDF 的页面图片 Base64 数组（仅 isScanned=true 时有内容） */
  pageImages?: string[];
  /** 总页数 */
  pageCount: number;
}

/** PDF 页面渲染为图片的结果 */
export interface PdfPageImage {
  pageNumber: number;
  /** Base64 data URL (image/jpeg) */
  dataUrl: string;
}

// ============================================================
// 主入口：自动识别并解析
// ============================================================

/**
 * 根据文件类型自动选择合适的解析策略
 */
export async function extractDocumentText(file: File): Promise<ParsedDocument> {
  const extension = file.name.split('.').pop()?.toLowerCase();

  switch (extension) {
    case 'txt':
      return extractTxt(file);

    case 'docx':
      return extractDocx(file);

    case 'pdf':
      return extractPdf(file);

    default:
      return {
        text: `无法解析的文件格式：.${extension}，请上传 PDF、Word 或 TXT 格式的简历文件。`,
        source: 'txt',
        isScanned: false,
        fileName: file.name,
        pageCount: 0,
      };
  }
}

// ============================================================
// TXT 解析
// ============================================================

async function extractTxt(file: File): Promise<ParsedDocument> {
  const text = await file.text();
  return {
    text,
    source: 'txt',
    isScanned: false,
    fileName: file.name,
    pageCount: 1,
  };
}

// ============================================================
// DOCX 解析（mammoth.js）
// ============================================================

async function extractDocx(file: File): Promise<ParsedDocument> {
  const buffer = await file.arrayBuffer();

  try {
    const result = await mammoth.extractRawText({ arrayBuffer: buffer });
    const text = result.value.trim();

    if (!text || text.length < 5) {
      return {
        text: `文件「${file.name}」解析后内容过短，可能是空白文档或内容为纯图片。请尝试粘贴简历文本。`,
        source: 'docx',
        isScanned: false,
        fileName: file.name,
        pageCount: 1,
      };
    }

    return {
      text,
      source: 'docx',
      isScanned: false,
      fileName: file.name,
      pageCount: 1,
    };
  } catch (err) {
    console.error('DOCX parse error:', err);
    return {
      text: `解析 Word 文档「${file.name}」时出错：${err instanceof Error ? err.message : '未知错误'}。请尝试粘贴简历文本。`,
      source: 'docx',
      isScanned: false,
      fileName: file.name,
      pageCount: 1,
    };
  }
}

// ============================================================
// PDF 解析（pdf.js：文本提取 → 检测扫描件 → Canvas 渲染）
// ============================================================

async function extractPdf(file: File): Promise<ParsedDocument> {
  const buffer = await file.arrayBuffer();

  try {
    const pdf = await pdfjsLib.getDocument({ data: new Uint8Array(buffer) }).promise;
    const totalPages = pdf.numPages;

    // 第一步：尝试文本提取
    const pageTexts: string[] = [];
    for (let i = 1; i <= totalPages; i++) {
      try {
        const page = await pdf.getPage(i);
        const content = await page.getTextContent();
        const rawText = content.items
          .map((item: { str?: string }) => item.str || '')
          .join('');
        // 后处理：清理 PDF 常见的问题
        pageTexts.push(normalizePdfText(rawText));
      } catch {
        pageTexts.push('');
      }
    }

    const fullText = pageTexts.join('\n\n').trim();

    // ===== 诊断日志 =====
    console.log('[DocumentParser.extractPdf] === PDF 文本提取完成 ===');
    console.log('[DocumentParser.extractPdf] 总页数:', totalPages);
    console.log('[DocumentParser.extractPdf] 提取文本长度:', fullText.length);
    console.log('[DocumentParser.extractPdf] 前300字符预览:', fullText.slice(0, 300));

    // 第二步：检测是否为扫描版 PDF（改进版阈值）
    if (isScannedPdf(fullText, totalPages)) {
      console.log(`[DocumentParser] 检测到扫描版 PDF（${totalPages}页），渲染为图片供 Vision 使用`);

      // 渲染所有页面为 Base64 图片
      const images: string[] = [];
      for (let i = 1; i <= totalPages; i++) {
        try {
          const page = await pdf.getPage(i);
          const image = await renderPageToImage(page, i);
          images.push(image.dataUrl);
        } catch (err) {
          console.error(`[DocumentParser] 第${i}页渲染失败:`, err);
        }
      }

      return {
        text: `[扫描版PDF] ${file.name}，共 ${totalPages} 页，已将页面转为图片供 AI 识读`,
        source: 'pdf_scanned',
        isScanned: true,
        fileName: file.name,
        pageImages: images,
        pageCount: totalPages,
      };
    }

    // 文本型 PDF：直接返回提取的文本
    if (!fullText || fullText.length < 10) {
      return {
        text: `PDF 文件「${file.name}」未能提取到有效文本内容，可能是扫描版或加密文档。`,
        source: 'pdf_text',
        isScanned: false,
        fileName: file.name,
        pageCount: totalPages,
      };
    }

    return {
      text: fullText,
      source: 'pdf_text',
      isScanned: false,
      fileName: file.name,
      pageCount: totalPages,
    };
  } catch (err) {
    console.error('PDF parse error:', err);
    return {
      text: `解析 PDF 文件「${file.name}」时出错：${err instanceof Error ? err.message : '未知错误'}。请尝试粘贴简历文本。`,
      source: 'pdf_text',
      isScanned: false,
      fileName: file.name,
      pageCount: 0,
    };
  }
}

// ============================================================
// PDF 文本规范化
// ============================================================

/**
 * 清理 PDF 文本提取的常见问题：
 * 1. CJK 字符间多余空格："姓 名" → "姓名"
 * 2. 多余换行和空白
 * 3. 全角/半角标点统一
 */
function normalizePdfText(text: string): string {
  let cleaned = text;

  // 1. 移除 CJK 字符之间的多余空格
  //    中文/日文/韩文字符后面紧跟空格再接 CJK → 移除该空格
  cleaned = cleaned.replace(/([\u4e00-\u9fff\u3040-\u309f\u30a0-\u30ff\uac00-\ud7af])\s+([\u4e00-\u9fff\u3040-\u309f\u30a0-\u30ff\uac00-\ud7af])/g, '$1$2');

  // 2. 中文冒号/逗号前的不必要空格
  cleaned = cleaned.replace(/\s+([：；，。！？、])/g, '$1');

  // 3. 无意义的多余换行（保留段落间双换行）
  cleaned = cleaned.replace(/\n{3,}/g, '\n\n');

  // 4. PDF 常出现的零宽字符
  cleaned = cleaned.replace(/[\u200b\u200c\u200d\u200e\u200f\ufeff]/g, '');

  // 5. 多余空格（> 2 个连续空格 → 1 个）
  cleaned = cleaned.replace(/ {3,}/g, '  ').trim();

  return cleaned;
}

// ============================================================
// 检测扫描版 PDF（改进版）
// ============================================================

/**
 * 判断是否为扫描版 PDF
 * 多维度检测策略：
 *   1. 文本完全为空 → 扫描版
 *   2. 每页平均 CJK 字符 < 8 → 扫描版
 *   3. 文本严重碎片化（大量单字符行） → 可能是扫描版但 pdf.js 勉强提取到
 */
function isScannedPdf(text: string, totalPages: number): boolean {
  if (!text) return true;

  // 去除规范化后剩余的空白再统计
  const compactText = text.replace(/\s+/g, '');
  if (compactText.length < 10) return true; // 几乎无内容

  const chineseCharCount = (text.match(/[\u4e00-\u9fff]/g) || []).length;
  const englishWordCount = text.split(/\s+/).filter(w => w.length > 1).length;
  const totalContent = chineseCharCount + englishWordCount;

  // 平均每页 CJK 字符 < 8 → 扫描版（正常文本 PDF 至少几十个/页）
  const avgPerPage = totalContent / Math.max(totalPages, 1);
  if (avgPerPage < 8) return true;

  // 检测碎片化：单独成行的单字符过多 → 可能是扫描版弱提取
  const lines = text.split('\n').filter(l => l.trim().length === 1);
  if (lines.length > 10 && lines.length > text.split('\n').length * 0.3) return true;

  return false;
}

// ============================================================
// PDF 页面 → Canvas → Base64
// ============================================================

/**
 * 将 PDF 页面渲染为 Base64 JPEG
 * @param page pdf.js Page 对象
 * @param pageNumber 页码（仅用于日志）
 * @returns 图片数据
 */
async function renderPageToImage(
  page: pdfjsLib.PDFPageProxy,
  pageNumber: number
): Promise<PdfPageImage> {
  const scale = 2.0; // 2x 分辨率确保 OCR 精度
  const viewport = page.getViewport({ scale });

  // 使用 OffscreenCanvas 避免 DOM 依赖（Vite 构建时可能走 SSR）
  const canvas = typeof OffscreenCanvas !== 'undefined'
    ? new OffscreenCanvas(viewport.width, viewport.height)
    : document.createElement('canvas');

  if (canvas instanceof HTMLCanvasElement) {
    canvas.width = viewport.width;
    canvas.height = viewport.height;
  }

  const ctx = canvas.getContext('2d');
  if (!ctx) {
    throw new Error(`第${pageNumber}页：无法获取 Canvas 渲染上下文`);
  }

  await page.render({
    canvasContext: ctx as unknown as CanvasRenderingContext2D,
    viewport,
  }).promise;

  // OffscreenCanvas → Blob → Base64
  const blob = canvas instanceof OffscreenCanvas
    ? await canvas.convertToBlob({ type: 'image/jpeg', quality: 0.85 })
    : await new Promise<Blob>((resolve) =>
        (canvas as HTMLCanvasElement).toBlob(r => resolve(r!), 'image/jpeg', 0.85)
      );

  const dataUrl = await blobToDataUrl(blob);

  return { pageNumber, dataUrl };
}

/** Blob → Base64 data URL */
function blobToDataUrl(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = () => reject(new Error('Blob 转 Base64 失败'));
    reader.readAsDataURL(blob);
  });
}

/* ============================================================
   意图识别规则引擎 — 独立于 AgentEngine 的可测试模块
   v1.1: 修复 5 个规则匹配缺陷
   ============================================================ */

import type { ConversationState, IntentType } from '../types';

/**
 * 基于规则匹配意图（不依赖 LLM）
 *
 * @param content - 用户消息（已去除 @提及）
 * @param currentState - 当前会话状态
 * @returns 识别到的意图，或 null（需降级到 LLM 或 FALLBACK）
 */
export function matchIntent(content: string, currentState: ConversationState): IntentType | null {
  // ──────── 简历修改检测（优先级最高，防止被 MODIFY_JD 误吞） ────────
  const resumeFieldPattern = /(?:姓名|年龄|学历|学校|院校|专业|工作年限|城市|所在地|技能|经历|简历|解析|手机号|邮箱)/;
  const modifyPattern = /修改|改成|改为|更正|纠正|调整|更新|加上|去掉|增加|减少|删除|添加|update|change|set|modify/i;
  if (resumeFieldPattern.test(content) && modifyPattern.test(content)) {
    return 'MODIFY_RESUME';
  }

  // ──────── JD 确认状态下 ────────
  if (currentState === 'JD_CONFIRMING') {
    // 短确认词 → 确认JD
    if (/^(确认|ok|就这样|没问题|可以|好的|行|好|是的|对|嗯|OK|Yes|Y)$/i.test(content.trim()) && content.length < 5) {
      return 'CONFIRM_JD';
    }
    // 包含修改意图 → 修改JD
    // 注意: 如果含简历字段，已被上面的 MODIFY_RESUME 拦截
    if (modifyPattern.test(content)) return 'MODIFY_JD';
  }

  // ──────── 筛选结果状态下 ────────
  if (currentState === 'SCREENING_RESULT') {
    const nameMatch = content.match(/查看\s*(.+?)\s*(的)?(详情|评分)/);
    if (nameMatch) return 'VIEW_DETAIL';
  }

  // ──────── 全局规则（优先级从高到低） ────────

  // 1. 查看详情/评分（先于筛选，因为 "查看评分" 含 "评分"）
  //    同时处理 "查看招聘进度" → 进度查询（含"招"但要优先匹配"进度"）
  if (/查看.*(详情|评分)/i.test(content)) {
    return 'VIEW_DETAIL';
  }

  // 1b. "看看这批" → 筛选（先于进度，因为 "看看这批怎么样" 含 "怎么样"）
  if (/看看这批/i.test(content)) {
    return 'SCREEN_RESUMES';
  }

  // 2. 进度查询（先于 JD 生成，因为 "招聘进度" 含 "招"）
  if (/进度|情况|怎么样|多少份|报告/i.test(content) && !/招|jd|岗位/i.test(content)) {
    return 'QUERY_PROGRESS';
  }

  // 2b. "查看.*进度" / "招聘.*进度" / "进度怎么样" → 含"招"但也有"进度"，优先进度
  if (/查看.*进度|招聘.*进度|招.*进度/.test(content)) {
    return 'QUERY_PROGRESS';
  }

  // 3. JD 生成
  if (/招|jd|岗位|招聘|hire/i.test(content) && !/进度|情况|怎么样/i.test(content) && !resumeFieldPattern.test(content)) {
    return 'GENERATE_JD';
  }

  // 4. 筛选评分
  if (/筛选|打分|打分|评分|看看这批/i.test(content) && !/查看/i.test(content)) {
    return 'SCREEN_RESUMES';
  }

  // 5. 长文本/文件引用 → 简历提交
  if (content.length > 200 || /\.(pdf|doc|docx)/i.test(content)) return 'SUBMIT_RESUME';

  // 6. JD 确认（仅 JD_CONFIRMING 状态 — 全局兜底）
  if (currentState === 'JD_CONFIRMING' &&
      /^(确认|ok|就这样|没问题|好的|行|好|是的|对|嗯)\s*$/i.test(content.trim()) && content.length < 10) {
    return 'CONFIRM_JD';
  }

  return null;
}

/* ============================================================
   LLM Client — OpenAI-compatible API 客户端
   支持 streaming、参数配置、错误处理
   ============================================================ */

// === LLM 配置类型 ===
export interface LLMConfig {
  enabled: boolean;
  apiKey: string;
  baseUrl: string;       // e.g. https://api.openai.com/v1
  model: string;          // e.g. gpt-4o-mini
  temperature: number;
  maxTokens: number;
  timeout: number;        // ms
}

export const DEFAULT_LLM_CONFIG: LLMConfig = {
  enabled: false,
  apiKey: '',
  baseUrl: 'https://ark.cn-beijing.volces.com/api/v3',
  model: 'doubao-seed-2-1-turbo-260628',
  temperature: 0.7,
  maxTokens: 4096,
  timeout: 60000,
};

// === LLM 消息格式 ===

/** 多模态内容块（Vision 模式） */
export interface TextContent {
  type: 'text';
  text: string;
}

export interface ImageContent {
  type: 'image_url';
  image_url: { url: string; detail?: 'low' | 'high' | 'auto' };
}

export type MultimodalContent = TextContent | ImageContent;

export interface LLMMessage {
  role: 'system' | 'user' | 'assistant';
  /** 纯文本模式用 string，多模态模式用 MultimodalContent[] */
  content: string | MultimodalContent[];
}

export interface LLMCallOptions {
  systemPrompt?: string;
  messages: LLMMessage[];
  temperature?: number;
  maxTokens?: number;
  stream?: boolean;
}

export interface LLMStreamChunk {
  content: string;
  done: boolean;
}

// === 事件回调 ===
export interface StreamCallbacks {
  onToken?: (token: string) => void;
  onComplete?: (fullText: string) => void;
  onError?: (error: Error) => void;
}

// ============================================================
// LLM Client 类
// ============================================================
export class LLMClient {
  private config: LLMConfig;

  constructor(config: Partial<LLMConfig> = {}) {
    this.config = { ...DEFAULT_LLM_CONFIG, ...config };
  }

  /** 更新配置 */
  updateConfig(updates: Partial<LLMConfig>) {
    this.config = { ...this.config, ...updates };
  }

  /** 获取当前配置 */
  getConfig(): Readonly<LLMConfig> {
    return this.config;
  }

  /** 非流式调用 — 返回完整响应 */
  async complete(options: LLMCallOptions): Promise<string> {
    const messages: LLMMessage[] = [];
    if (options.systemPrompt) {
      messages.push({ role: 'system', content: options.systemPrompt });
    }
    messages.push(...options.messages);

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), this.config.timeout);

    try {
      const response = await fetch(`${this.config.baseUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${this.config.apiKey}`,
        },
        body: JSON.stringify({
          model: this.config.model,
          messages,
          temperature: options.temperature ?? this.config.temperature,
          max_tokens: options.maxTokens ?? this.config.maxTokens,
          stream: false,
        }),
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errText = await response.text().catch(() => 'Unknown error');
        throw new LLMError(`LLM API error ${response.status}: ${errText}`, response.status);
      }

      const data = await response.json();
      const content = data.choices?.[0]?.message?.content || '';
      return content;
    } catch (err) {
      clearTimeout(timeoutId);
      if (err instanceof LLMError) throw err;
      if (err instanceof DOMException && err.name === 'AbortError') {
        throw new LLMError('LLM request timed out', 408);
      }
      throw new LLMError(`LLM request failed: ${(err as Error).message}`, 0);
    }
  }

  /** 流式调用 — 通过回调返回增量文本 */
  async streamComplete(options: LLMCallOptions, callbacks: StreamCallbacks): Promise<string> {
    const messages: LLMMessage[] = [];
    if (options.systemPrompt) {
      messages.push({ role: 'system', content: options.systemPrompt });
    }
    messages.push(...options.messages);

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), this.config.timeout);

    try {
      const response = await fetch(`${this.config.baseUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${this.config.apiKey}`,
        },
        body: JSON.stringify({
          model: this.config.model,
          messages,
          temperature: options.temperature ?? this.config.temperature,
          max_tokens: options.maxTokens ?? this.config.maxTokens,
          stream: true,
        }),
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errText = await response.text().catch(() => 'Unknown error');
        throw new LLMError(`LLM API error ${response.status}: ${errText}`, response.status);
      }

      const reader = response.body?.getReader();
      if (!reader) throw new LLMError('No response body for streaming', 0);

      const decoder = new TextDecoder();
      let fullText = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });
        const lines = chunk.split('\n').filter(line => line.startsWith('data: '));

        for (const line of lines) {
          const data = line.slice(6).trim();
          if (data === '[DONE]') continue;

          try {
            const parsed = JSON.parse(data);
            const delta = parsed.choices?.[0]?.delta?.content;
            if (delta) {
              fullText += delta;
              callbacks.onToken?.(delta);
            }
          } catch {
            // 跳过无法解析的行
          }
        }
      }

      callbacks.onComplete?.(fullText);
      return fullText;

    } catch (err) {
      clearTimeout(timeoutId);
      if (err instanceof LLMError) {
        callbacks.onError?.(err);
        throw err;
      }
      if (err instanceof DOMException && err.name === 'AbortError') {
        const timeoutErr = new LLMError('LLM request timed out', 408);
        callbacks.onError?.(timeoutErr);
        throw timeoutErr;
      }
      const wrappedErr = new LLMError(`LLM request failed: ${(err as Error).message}`, 0);
      callbacks.onError?.(wrappedErr);
      throw wrappedErr;
    }
  }

  // ============================================================
  // Vision / 多模态方法
  // ============================================================

  /**
   * 使用 LLM Vision 能力解析扫描版简历
   * 将 PDF 页面图片作为多模态输入，直接让模型"看"简历图片
   *
   * @param pageImages - Base64 data URL 数组（来自 DocumentParser）
   * @param fileName - 原始文件名（用于上下文）
   */
  async parseResumeWithVision(pageImages: string[], fileName: string): Promise<string> {
    const imageContents: ImageContent[] = pageImages.map(url => ({
      type: 'image_url' as const,
      image_url: { url, detail: 'high' as const },
    }));

    const userContent: MultimodalContent[] = [
      { type: 'text', text: RESUME_VISION_PROMPT.replace('{fileName}', fileName) },
      ...imageContents,
    ];

    const messages: LLMMessage[] = [
      { role: 'system', content: RESUME_VISION_SYSTEM_PROMPT },
      { role: 'user', content: userContent },
    ];

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), this.config.timeout);

    try {
      const response = await fetch(`${this.config.baseUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${this.config.apiKey}`,
        },
        body: JSON.stringify({
          model: this.config.model,
          messages,
          temperature: 0.2,    // 低温度确保提取准确
          max_tokens: this.config.maxTokens,
          stream: false,
        }),
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errText = await response.text().catch(() => 'Unknown error');
        throw new LLMError(`Vision API error ${response.status}: ${errText}`, response.status);
      }

      const data = await response.json();
      const content = data.choices?.[0]?.message?.content || '';
      return content;
    } catch (err) {
      clearTimeout(timeoutId);
      if (err instanceof LLMError) throw err;
      if (err instanceof DOMException && err.name === 'AbortError') {
        throw new LLMError('Vision request timed out', 408);
      }
      throw new LLMError(`Vision request failed: ${(err as Error).message}`, 0);
    }
  }

  /**
   * 检查当前配置的模型是否支持 Vision（多模态）
   * 已知支持 Vision 的模型：
   *   gpt-4o, gpt-4o-mini, gpt-4-turbo, gpt-4-vision-preview
   *   gemini-2.5-flash, gemini-2.5-pro, gemini-2.0-flash
   *   claude-sonnet-4-*, claude-3-5-sonnet
   *   qwen-vl-*, qwen2.5-vl-*
   *   glm-4v, cogvlm-*
   *   deepseek-chat（部分版本支持）
   */
  supportsVision(): boolean {
    const model = this.config.model.toLowerCase();
    const visionModels = [
      'gpt-4o', 'gpt-4-turbo', 'gpt-4-vision',
      'gemini', 'gemini-2', 'gemini-pro-vision',
      'claude-3-5', 'claude-sonnet-4', 'claude-3-opus',
      'qwen-vl', 'qwen2.5-vl',
      'glm-4v', 'cogvlm',
      'pixtral', 'llava',
    ];
    return visionModels.some(prefix => model.includes(prefix));
  }
}

// ============================================================
// LLM 错误类
// ============================================================
export class LLMError extends Error {
  statusCode: number;

  constructor(message: string, statusCode: number) {
    super(message);
    this.name = 'LLMError';
    this.statusCode = statusCode;
  }
}

// ============================================================
// 全局 LLM Client 单例
// ============================================================
let llmClientInstance: LLMClient | null = null;

export function getLLMClient(config?: Partial<LLMConfig>): LLMClient {
  if (!llmClientInstance) {
    llmClientInstance = new LLMClient(config);
  }
  if (config) {
    llmClientInstance.updateConfig(config);
  }
  return llmClientInstance;
}

export function resetLLMClient(): void {
  llmClientInstance = null;
}

