let agentInstance: ResumeParserAgent | null = null;

export function getResumeParserAgent(config?: Partial<LLMConfig>): ResumeParserAgent {
  if (!agentInstance) {
    agentInstance = new ResumeParserAgent(config);
  }
  return agentInstance;
}

