  agentInstance = null;
}

/* ============================================================
   Secure Storage — Web Crypto API 加密存储

   使用 AES-GCM 加密敏感数据（如 API Key）后再写入 localStorage。
   派生密钥基于浏览器指纹 (UserAgent + 屏幕尺寸) 的 SHA-256 摘要。
   注意：此方案不防物理访问，仅防止明文泄露到磁盘。
   ============================================================ */

const KEY_PREFIX = 'recruitment-agent-secure:';
const ENCRYPTION_ALGO = { name: 'AES-GCM', length: 256 } as const;

/** 基于浏览器环境派生加密密钥 */
async function deriveKey(): Promise<CryptoKey> {
  const enc = new TextEncoder();
  const material = await crypto.subtle.digest(
    'SHA-256',
    enc.encode(navigator.userAgent + screen.width + screen.height + 'recruitment-agent-salt'),
  );
  return crypto.subtle.importKey('raw', material, ENCRYPTION_ALGO, false, ['encrypt', 'decrypt']);
}

/** 加密并存储到 localStorage */
export async function secureSet(key: string, value: string): Promise<void> {
  if (!value) {
    localStorage.removeItem(KEY_PREFIX + key);
    return;
  }
  const cryptoKey = await deriveKey();
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const enc = new TextEncoder();
  const encrypted = await crypto.subtle.encrypt(
    { ...ENCRYPTION_ALGO, iv },
    cryptoKey,
    enc.encode(value),
  );
  // 存储格式: iv(12 bytes) + ciphertext → Base64
  const combined = new Uint8Array(iv.length + encrypted.byteLength);
  combined.set(iv);
  combined.set(new Uint8Array(encrypted), iv.length);
  localStorage.setItem(KEY_PREFIX + key, btoa(String.fromCharCode(...combined)));
}

/** 从 localStorage 解密读取 */
export async function secureGet(key: string): Promise<string | null> {
  const stored = localStorage.getItem(KEY_PREFIX + key);
  if (!stored) return null;
  try {
    const combined = Uint8Array.from(atob(stored), c => c.charCodeAt(0));
    const iv = combined.slice(0, 12);
    const ciphertext = combined.slice(12);
    const cryptoKey = await deriveKey();
    const decrypted = await crypto.subtle.decrypt(
      { ...ENCRYPTION_ALGO, iv },
      cryptoKey,
      ciphertext,
    );
    return new TextDecoder().decode(decrypted);
  } catch {
    // 解密失败（跨浏览器/隐私模式等）→ 清除损坏数据
    localStorage.removeItem(KEY_PREFIX + key);
    return null;
  }
}

/** 删除加密存储 */
export function secureRemove(key: string): void {
  localStorage.removeItem(KEY_PREFIX + key);
}

/** 对已保存的 Key 生成掩码显示（前4后4） */
export function maskKey(key: string): string {
  if (key.length <= 8) return '****';
  return key.slice(0, 4) + '****' + key.slice(-4);
}

/* ============================================================
   状态机模块 — 会话状态转换规则 (P1 修复 B-4)

   核心职责:
     1. 定义合法状态转换矩阵 (VALID_TRANSITIONS)
     2. 提供 canTransition() 校验函数
     3. 在非法转换时给出诊断信息

   使用方式:
     - recruitmentStore.ts 的 setState 调用 canTransition 做前置校验
     - 防止状态卡死和无效转换
   ============================================================ */

import type { ConversationState } from '../types';

// ============================================================
// 状态转换矩阵
// ============================================================

/** 每个状态允许转换到的目标状态集合 */
export const VALID_TRANSITIONS: Record<ConversationState, ReadonlySet<ConversationState>> = {
  IDLE: new Set<ConversationState>([
    'JD_GENERATING',  // 用户开始生成JD
    'COLLECTING',      // 用户直接提交简历（跳过JD）
  ]),

  JD_GENERATING: new Set<ConversationState>([
    'JD_CONFIRMING',   // JD生成成功，等待确认
    'IDLE',            // 异常/重置
  ]),

  JD_CONFIRMING: new Set<ConversationState>([
    'JD_GENERATING',   // 用户修改JD → 重新生成
    'COLLECTING',      // 用户确认JD → 进入简历收集
    'IDLE',            // 异常/重置
  ]),

  COLLECTING: new Set<ConversationState>([
    'SCREENING',       // 触发筛选评分
    'JD_GENERATING',   // 重新生成JD
    'SCREENING_RESULT', // 已有筛选结果可查
    'IDLE',            // 异常/重置
  ]),

  SCREENING: new Set<ConversationState>([
    'SCREENING_RESULT', // 评分完成
    'IDLE',             // 异常/重置
  ]),

  SCREENING_RESULT: new Set<ConversationState>([
    'COLLECTING',      // 继续添加简历
    'SCREENING',       // 重新筛选
    'JD_GENERATING',   // 新建岗位
    'IDLE',            // 异常/重置
  ]),
};

// ============================================================
// 状态转换校验
// ============================================================

export interface TransitionResult {
  allowed: boolean;
  /** 非法转换时的诊断消息 */
  reason?: string;
}

/**
 * 校验状态转换是否合法
 *
 * @param from - 当前状态
 * @param to - 目标状态
 * @returns 校验结果（允许/拒绝 + 原因）
 */
export function canTransition(from: ConversationState, to: ConversationState): TransitionResult {
  // 同一状态 → 无害，允许（避免重复 setState 触发报警）
  if (from === to) {
    return { allowed: true };
  }

  const allowedTargets = VALID_TRANSITIONS[from];

  if (!allowedTargets) {
    return {
      allowed: false,
      reason: `未知当前状态 '${from}'`,
    };
  }

  if (allowedTargets.has(to)) {
    return { allowed: true };
  }

  return {
    allowed: false,
    reason: `非法状态转换: ${from} → ${to}。允许的目标状态: ${[...allowedTargets].join(', ')}`,
  };
}

/**
 * 获取某状态的所有合法目标状态（用于 UI 和调试）
 */
export function getAllowedTargets(from: ConversationState): ConversationState[] {
  const targets = VALID_TRANSITIONS[from];
  return targets ? [...targets] : [];
}

/**
 * 生成状态转换矩阵的人类可读描述（用于文档）
 */
export function describeTransitions(): string {
  return Object.entries(VALID_TRANSITIONS)
    .map(([from, targets]) => `${from} → ${[...targets].join(' | ')}`)
    .join('\n');
}

